SELECT specialization_id, COUNT(name) AS designer_count
FROM designers
GROUP BY specialization_id;

SELECT project_id, AVG(rating) AS average_rating
FROM project_ratings
GROUP BY project_id;

SELECT designer_id, project_id, role
FROM designer_projects
WHERE role = 'UX Designer';

SELECT message, sent_at, user_id
FROM project_messages
WHERE project_id = 1;

SELECT name
FROM designers
ORDER BY name ASC;

SELECT COUNT(*) AS message_count
FROM project_messages
WHERE project_id = 1;
